import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
} from "@mui/material";

import { doctors } from "../data/doctors"; // fixed import

const DoctorProfile = () => {
  const { doctorId } = useParams(); // ← must be INSIDE the component

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  if (!doctor) {
    return (
      <Container sx={{ py: 8 }}>
        <Typography variant="h5" align="center" color="error">
          Doctor not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 6 }}>
      <Paper elevation={4} sx={{ p: 4, borderRadius: 3 }}>
        <Grid container spacing={4}>
          {/* Left column - photo + name */}
          <Grid item xs={12} md={4} sx={{ textAlign: "center" }}>
            <Avatar
              src={doctor.image}
              alt={doctor.name}
              sx={{ width: 200, height: 200, mx: "auto", mb: 2 }}
            />
            <Typography variant="h5" gutterBottom>
              {doctor.name}
            </Typography>
            <Typography variant="subtitle1" color="primary">
              {doctor.specialty}
            </Typography>
          </Grid>

          {/* Right column - details */}
          <Grid item xs={12} md={8}>
            <Typography variant="h6" gutterBottom>
              Professional Details
            </Typography>
            <Divider sx={{ mb: 2 }} />

            <List disablePadding>
              <ListItem>
                <ListItemText
                  primary="Experience"
                  secondary={doctor.experience}
                />
              </ListItem>
              <ListItem>
                <ListItemText
                  primary="Qualification"
                  secondary={doctor.qualification}
                />
              </ListItem>
              <ListItem>
                <ListItemText
                  primary="Availability"
                  secondary={doctor.availability}
                />
              </ListItem>
              <ListItem sx={{ alignItems: "flex-start" }}>
                <ListItemText primary="About" secondary={doctor.bio} />
              </ListItem>
            </List>

            <Box sx={{ mt: 4, textAlign: "center" }}>
              <Button variant="contained" color="primary" size="large">
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
